  <!-- Header -->
  <div class="mb-10">
    <h1 class="font-display text-4xl font-bold text-zinc-900 dark:text-white mb-2">
      Projects
    </h1>
    <p class="text-zinc-500 dark:text-zinc-400">
      Case studies — click any card to read the full breakdown.
    </p>
  </div>

  <!-- ── FILTERS ──────────────────────────────────── -->
  <div class="rounded-2xl border border-zinc-200 dark:border-zinc-800
              bg-zinc-50 dark:bg-zinc-900 p-5 mb-8 space-y-5">

    <!-- Category -->
    <div>
      <p class="text-xs font-semibold uppercase tracking-widest text-zinc-400 mb-3 font-mono">
        Category
      </p>
      <div class="flex flex-wrap gap-2">
        <button
          *ngFor="let tag of availableTags()"
          (click)="selectTag(tag)"
          [class]="selectedTag() === tag
            ? 'px-4 py-1.5 rounded-full text-sm font-medium bg-accent text-white transition-all'
            : 'px-4 py-1.5 rounded-full text-sm font-medium border border-zinc-200 dark:border-zinc-700
               text-zinc-500 dark:text-zinc-400 hover:border-accent hover:text-accent transition-all'">
          {{ tag }}
        </button>
      </div>
    </div>

    <!-- Tech stack -->
    <div>
      <p class="text-xs font-semibold uppercase tracking-widest text-zinc-400 mb-3 font-mono">
        Tech stack
      </p>
      <div class="flex flex-wrap gap-2">
        <button
          *ngFor="let tech of availableTech()"
          (click)="toggleTech(tech)"
          [class]="isTechSelected(tech)
            ? 'px-3 py-1 rounded-md text-xs font-mono font-semibold bg-indigo-50 dark:bg-indigo-950
               text-accent border border-accent transition-all'
            : 'px-3 py-1 rounded-md text-xs font-mono border border-zinc-200 dark:border-zinc-700
               text-zinc-400 hover:border-accent hover:text-accent transition-all'">
          {{ tech }}
        </button>
      </div>
    </div>

    <!-- Clear + count -->
    <div class="flex items-center justify-between pt-1">
      <p class="text-sm text-zinc-400">
        Showing
        <span class="font-semibold text-zinc-700 dark:text-zinc-200">{{ filteredProjects().length }}</span>
        of {{ allProjects().length }} projects
      </p>
      <button
        *ngIf="activeFilterCount() > 0"
        (click)="clearAllFilters()"
        class="flex items-center gap-2 text-sm text-zinc-400 hover:text-red-500 transition-colors">
        Clear filters
        <span class="w-5 h-5 flex items-center justify-center rounded-full
                     bg-red-100 dark:bg-red-950 text-red-500 text-xs font-bold">
          {{ activeFilterCount() }}
        </span>
      </button>
    </div>
  </div>

  <!-- ── PROJECT GRID ──────────────────────────────── -->
  <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
    <a
      *ngFor="let project of filteredProjects(); let i = index"
      [routerLink]="['/projects', project.id]"
      class="group flex flex-col rounded-2xl overflow-hidden border border-zinc-200 dark:border-zinc-800
             bg-white dark:bg-zinc-900 hover:border-accent dark:hover:border-accent
             hover:-translate-y-1 hover:shadow-xl hover:shadow-indigo-100 dark:hover:shadow-indigo-950/30
             transition-all duration-200 animate-fade-up no-underline"
      [style.animation-delay]="(i * 60) + 'ms'">

      <!-- Thumbnail -->
      <div class="overflow-hidden aspect-video bg-zinc-100 dark:bg-zinc-800">
        <img [src]="project.thumbnail" [alt]="project.title"
             class="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"/>
      </div>

      <!-- Body -->
      <div class="flex flex-col flex-1 p-5 gap-3">
        <div>
          <h2 class="font-display font-bold text-zinc-900 dark:text-white text-lg leading-tight mb-1">
            {{ project.title }}
          </h2>
          <p class="text-sm text-zinc-500 dark:text-zinc-400 leading-relaxed">
            {{ project.tagline }}
          </p>
        </div>

        <!-- Category tags -->
        <div class="flex flex-wrap gap-1.5 mt-auto">
          <span *ngFor="let tag of project.tags"
                class="px-2.5 py-0.5 rounded-full text-xs font-medium
                       bg-indigo-50 dark:bg-indigo-950/60 text-accent">
            {{ tag }}
          </span>
        </div>

        <!-- Tech chips -->
        <div class="flex flex-wrap gap-1.5">
          <span *ngFor="let tech of project.tech"
                [class]="isTechSelected(tech)
                  ? 'px-2 py-0.5 rounded text-xs font-mono border border-accent text-accent bg-indigo-50 dark:bg-indigo-950/40'
                  : 'px-2 py-0.5 rounded text-xs font-mono border border-zinc-200 dark:border-zinc-700 text-zinc-400'">
            {{ tech }}
          </span>
        </div>
      </div>
    </a>
  </div>

  <!-- Empty state -->
  <div *ngIf="filteredProjects().length === 0"
       class="flex flex-col items-center justify-center py-24 text-center">
    <p class="text-zinc-400 mb-4 text-lg">No projects match your filters.</p>
    <button (click)="clearAllFilters()"
            class="px-5 py-2.5 rounded-xl border border-zinc-200 dark:border-zinc-700
                   text-sm text-zinc-500 hover:border-accent hover:text-accent transition-all">
      Clear filters
    </button>
  </div>

</div>
